class Solution {
public:
    string mergeAlternately(string word1, string word2) {
        string result;
        int minLen = min(word1.size(), word2.size());

        for (int i = 0; i < minLen; ++i) {
            result += word1[i];
            result += word2[i];
        }

        result += word1.substr(minLen);
        result += word2.substr(minLen);

        return result;
    }
};
```
